"use client";

import { useState } from "react";
import { motion, AnimatePresence } from "framer-motion";
import { ChevronDown, FileText, Download } from "lucide-react";

// eslint-disable-next-line @typescript-eslint/no-explicit-any
export function InvestorClient({ dict }: { dict: any }) {
    const [openYear, setOpenYear] = useState<string | null>("2023");

    // Placeholder data to demonstrate the Layered Content strategy
    const reportsData = [
        {
            year: "2023",
            reports: [
                { title: "2023 Yıllık Faaliyet Raporu", size: "4.2 MB" },
                { title: "2023 4. Çeyrek Finansal Sonuçlar", size: "2.1 MB" },
                { title: "2023 Sürdürülebilirlik Raporu", size: "6.8 MB" }
            ]
        },
        {
            year: "2022",
            reports: [
                { title: "2022 Yıllık Faaliyet Raporu", size: "3.9 MB" },
                { title: "2022 4. Çeyrek Finansal Sonuçlar", size: "1.8 MB" }
            ]
        },
        {
            year: "2021",
            reports: [
                { title: "2021 Yıllık Faaliyet Raporu", size: "3.5 MB" }
            ]
        }
    ];

    return (
        <div className="mt-16 w-full max-w-4xl mx-auto">
            <h3 className="text-2xl font-bold text-gray-900 dark:text-white mb-8 border-b border-gray-200 dark:border-white/10 pb-4">
                Finansal Raporlar ve Yatırımcı Sunumları
            </h3>
            <div className="space-y-4">
                {reportsData.map((item) => (
                    <div key={item.year} className="border border-black/5 dark:border-white/5 rounded-xl overflow-hidden bg-white dark:bg-white/[0.02] shadow-sm">
                        <button
                            onClick={() => setOpenYear(openYear === item.year ? null : item.year)}
                            className="w-full flex items-center justify-between p-6 text-left hover:bg-black/5 dark:hover:bg-white/5 transition-colors"
                        >
                            <span className="text-xl font-bold text-gray-900 dark:text-white flex items-center gap-4">
                                <div className="p-2 bg-primary/10 rounded-lg text-primary">
                                    <FileText className="w-6 h-6" />
                                </div>
                                {item.year} Yılı Raporları
                            </span>
                            <ChevronDown className={`w-5 h-5 text-gray-500 transition-transform duration-300 ${openYear === item.year ? "rotate-180" : ""}`} />
                        </button>
                        <AnimatePresence>
                            {openYear === item.year && (
                                <motion.div
                                    initial={{ height: 0, opacity: 0 }}
                                    animate={{ height: "auto", opacity: 1 }}
                                    exit={{ height: 0, opacity: 0 }}
                                    className="overflow-hidden bg-gray-50 dark:bg-black/20"
                                >
                                    <div className="p-6 pt-2 flex flex-col gap-3">
                                        {item.reports.map((report, idx) => (
                                            <a 
                                                key={idx}
                                                href="#"
                                                className="flex items-center justify-between p-5 bg-white dark:bg-white/5 border border-black/5 dark:border-white/5 rounded-xl hover:border-primary/50 group transition-all"
                                                onClick={(e) => {
                                                    // Prevent 404 navigation for Mock data
                                                    e.preventDefault();
                                                    alert("Mock PDF will be downloaded.");
                                                }}
                                            >
                                                <span className="font-bold text-sm text-gray-700 dark:text-gray-300 group-hover:text-primary transition-colors">
                                                    {report.title}
                                                </span>
                                                <div className="flex items-center gap-4 text-xs font-bold uppercase tracking-widest text-gray-400">
                                                    <span>PDF ({report.size})</span>
                                                    <span className="w-10 h-10 rounded-lg bg-primary/10 flex items-center justify-center text-primary group-hover:bg-primary group-hover:text-white transition-colors">
                                                        <Download size={16} />
                                                    </span>
                                                </div>
                                            </a>
                                        ))}
                                    </div>
                                </motion.div>
                            )}
                        </AnimatePresence>
                    </div>
                ))}
            </div>
            
            {/* Added a coming soon badge just to retain the original meaning */}
            <div className="mt-16 text-center text-xs uppercase tracking-widest text-gray-400 font-bold">
                {dict.investor_page?.coming_soon_desc || "Detaylı portal yapım aşamasındadır."}
            </div>
        </div>
    );
}
